import React from "react";
import { ResponsiveElement, useSeparator } from "../../../../Factory";
import type {ITextComponent} from "@lmb/kitsconcerto-types";

const mapAsToSize: Record<string, ITextComponent["size"]> = {
    small: "sm",
    label: "sm",
    span: "md",
    p: "md",
};

const mapTextOverflowProps = (props: ITextComponent) => {
    let numberOfLines: number | undefined;
    let ellipsizeMode: "head" | "middle" | "tail" | "clip" | undefined;

    if (props.whiteSpace === "nowrap") {
        numberOfLines = 1;
    }

    if (props.textOverflow === "ellipsis") {
        ellipsizeMode = "tail";
    }

    if (props.textOverflow === "clip") {
        ellipsizeMode = "clip";
    }

    return { numberOfLines, ellipsizeMode };
};

const Text: React.FC<ITextComponent> = (props) => {
    const { cssProps, nativeProps } = useSeparator<any>(props);
    const {
        as = "p",
        size,
        children,
        isTruncated,
        bold,
        underline,
        strikeThrough,
        sub,
        italic,
        highlight,
        ...rest
    } = nativeProps;

    const resolvedSize = size || mapAsToSize[as] || "md";

    const overflowProps = mapTextOverflowProps(props);


    return (
        <ResponsiveElement
            as="Text"
            cssProps={{...cssProps}}
            additionalStyles={{
                padding:0
            }}
            nativeProps={{
                ...rest,
                as,
                size: resolvedSize,
                isTruncated,
                bold,
                underline,
                strikeThrough,
                sub,
                italic,
                highlight,
                ...overflowProps
            }}
        >
            {children}
        </ResponsiveElement>
    );
};

export default Text;
